class TransactionProcessor {
    static let shared = TransactionProcessor()
    
    private var accounts: [String: Account] = [:]
    private var transactions: [Transaction] = []
    
    init() {
        loadSampleAccounts()
    }
    
    private func loadSampleAccounts() {
        accounts["ACC001"] = Account(accountNumber: "ACC001", accountType: "Checking", balance: 5000.00, currency: "USD")
        accounts["ACC002"] = Account(accountNumber: "ACC002", accountType: "Savings", balance: 15000.00, currency: "USD")
    }
    
    func processTransaction(from: String, to: String, amount: Decimal) -> (success: Bool, message: String, transaction: Transaction?) {
        let transactionId = UUID().uuidString
        
        guard var fromAccount = accounts[from] else {
            return (false, "Source account not found", nil)
        }
        
        guard var toAccount = accounts[to] else {
            return (false, "Destination account not found", nil)
        }
        
        guard amount > 0 else {
            return (false, "Invalid transaction amount", nil)
        }
        
        guard fromAccount.balance >= amount else {
            let failedTransaction = Transaction(
                id: transactionId,
                fromAccount: from,
                toAccount: to,
                amount: amount,
                timestamp: Date(),
                type: .transfer,
                status: .failed
            )
            transactions.append(failedTransaction)
            return (false, "Insufficient funds", failedTransaction)
        }
        
        fromAccount.balance -= amount
        toAccount.balance += amount
        
        accounts[from] = fromAccount
        accounts[to] = toAccount
        
        let completedTransaction = Transaction(
            id: transactionId,
            fromAccount: from,
            toAccount: to,
            amount: amount,
            timestamp: Date(),
            type: .transfer,
            status: .completed
        )
        
        transactions.append(completedTransaction)
        saveTransactionSecurely(completedTransaction)
        
        return (true, "Transaction completed successfully", completedTransaction)
    }
    
    func deposit(to: String, amount: Decimal) -> (success: Bool, message: String) {
        guard var account = accounts[to] else {
            return (false, "Account not found")
        }
        
        guard amount > 0 else {
            return (false, "Invalid deposit amount")
        }
        
        account.balance += amount
        accounts[to] = account
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccount: "EXTERNAL",
            toAccount: to,
            amount: amount,
            timestamp: Date(),
            type: .deposit,
            status: .completed
        )
        
        transactions.append(transaction)
        saveTransactionSecurely(transaction)
        
        return (true, "Deposit completed successfully")
    }
    
    func withdraw(from: String, amount: Decimal) -> (success: Bool, message: String) {
        guard var account = accounts[from] else {
            return (false, "Account not found")
        }
        
        guard amount > 0 else {
            return (false, "Invalid withdrawal amount")
        }
        
        guard account.balance >= amount else {
            return (false, "Insufficient funds")
        }
        
        account.balance -= amount
        accounts[from] = account
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccount: from,
            toAccount: "EXTERNAL",
            amount: amount,
            timestamp: Date(),
            type: .withdrawal,
            status: .completed
        )
        
        transactions.append(transaction)
        saveTransactionSecurely(transaction)
        
        return (true, "Withdrawal completed successfully")
    }
    
    func getBalance(for accountNumber: String) -> Decimal? {
        return accounts[accountNumber]?.balance
    }
    
    func getAccount(for accountNumber: String) -> Account? {
        return accounts[accountNumber]
    }
    
    func getAllAccounts() -> [Account] {
        return Array(accounts.values)
    }
    
    func getTransactionHistory(for accountNumber: String) -> [Transaction] {
        return transactions.filter { $0.fromAccount == accountNumber || $0.toAccount == accountNumber }
    }
    
    private func saveTransactionSecurely(_ transaction: Transaction) {
        let transactionData = "\(transaction.id),\(transaction.fromAccount),\(transaction.toAccount),\(transaction.amount),\(transaction.timestamp),\(transaction.type.rawValue),\(transaction.status.rawValue)"
        SecureStorage.shared.save(key: "transaction_\(transaction.id)", value: transactionData)
    }
}

