        view.endEditing(true)
        
        guard let fromAccount = fromAccountField.text, !fromAccount.isEmpty,
              let toAccount = toAccountField.text, !toAccount.isEmpty,
              let amountText = amountField.text, !amountText.isEmpty,
              let amount = Decimal(string: amountText) else {
            showAlert(title: "Error", message: "Please fill in all fields with valid data")
            return
        }
        
        activityIndicator.startAnimating()
        transferButton.setTitle("", for: .normal)
        transferButton.isEnabled = false
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            let result = TransactionProcessor.shared.processTransaction(from: fromAccount, to: toAccount, amount: amount)
            
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                self?.transferButton.setTitle("Transfer", for: .normal)
                self?.transferButton.isEnabled = true
                
