                    self?.showAlert(title: "Success", message: result.message) {
                        self?.clearFields()
                        self?.navigationController?.popViewController(animated: true)
                    }
                } else {
                    self?.showAlert(title: "Transaction Failed", message: result.message)
                }
            }
        }
    }
    
