    }
    
    private func setupUI() {
        typeLabel.translatesAutoresizingMaskIntoConstraints = false
        typeLabel.font = UIFont.systemFont(ofSize: 16, weight: .medium)
        
        accountLabel.translatesAutoresizingMaskIntoConstraints = false
        accountLabel.font = UIFont.systemFont(ofSize: 14)
        accountLabel.textColor = .systemGray
        
        amountLabel.translatesAutoresizingMaskIntoConstraints = false
        amountLabel.font = UIFont.systemFont(ofSize: 18, weight: .bold)
        amountLabel.textAlignment = .right
        
        dateLabel.translatesAutoresizingMaskIntoConstraints = false
        dateLabel.font = UIFont.systemFont(ofSize: 12)
        dateLabel.textColor = .systemGray
        dateLabel.textAlignment = .right
        
        statusLabel.translatesAutoresizingMaskIntoConstraints = false
        statusLabel.font = UIFont.systemFont(ofSize: 12, weight: .medium)
        
        contentView.addSubview(typeLabel)
        contentView.addSubview(accountLabel)
        contentView.addSubview(amountLabel)
        contentView.addSubview(dateLabel)
        contentView.addSubview(statusLabel)
        
        NSLayoutConstraint.activate([
            typeLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            typeLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            accountLabel.topAnchor.constraint(equalTo: typeLabel.bottomAnchor, constant: 4),
            accountLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            statusLabel.topAnchor.constraint(equalTo: accountLabel.bottomAnchor, constant: 4),
            statusLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            statusLabel.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12),
            
            amountLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            amountLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            
            dateLabel.topAnchor.constraint(equalTo: amountLabel.bottomAnchor, constant: 4),
            dateLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16)
        ])
    }
    
    func configure(with transaction: Transaction, currentAccountNumber: String) {
        typeLabel.text = transaction.type.rawValue.capitalized
        
        if transaction.fromAccount == currentAccountNumber {
            accountLabel.text = "To: \(transaction.toAccount)"
            amountLabel.text = "-\(formatCurrency(transaction.amount))"
            amountLabel.textColor = .systemRed
        } else {
            accountLabel.text = "From: \(transaction.fromAccount)"
            amountLabel.text = "+\(formatCurrency(transaction.amount))"
            amountLabel.textColor = .systemGreen
        }
        
        dateLabel.text = formatDate(transaction.timestamp)
        
        statusLabel.text = transaction.status.rawValue.capitalized
        switch transaction.status {
        case .completed:
            statusLabel.textColor = .systemGreen
        case .pending:
            statusLabel.textColor = .systemOrange
        case .failed:
            statusLabel.textColor = .systemRed
        }
    }
    
    private func formatCurrency(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: amount as NSNumber) ?? "$0.00"
    }
    
    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

